import{_ as a,o as e,c as r,ag as d}from"./chunks/framework.CAXxHpAX.js";const b=JSON.parse('{"title":"高阶配置全攻略","description":"","frontmatter":{},"headers":[],"relativePath":"03-advanced.md","filePath":"03-advanced.md"}'),i={name:"03-advanced.md"};function s(o,t,h,n,l,c){return e(),r("div",null,[...t[0]||(t[0]=[d(`<h1 id="高阶配置全攻略" tabindex="-1">高阶配置全攻略 <a class="header-anchor" href="#高阶配置全攻略" aria-label="Permalink to &quot;高阶配置全攻略&quot;">​</a></h1><p>来源：<a href="https://mp.weixin.qq.com/s?__biz=MzY5NjIwNDE2MA==&amp;mid=2247486967&amp;idx=1&amp;sn=f4dcd97b97a55f9aa5075674c3dbf204" target="_blank" rel="noreferrer">尼克的AI笔记 - 揭秘Hermes高阶配置全攻略</a></p><h2 id="soul-md-迭代方式" tabindex="-1">SOUL.md 迭代方式 <a class="header-anchor" href="#soul-md-迭代方式" aria-label="Permalink to &quot;SOUL.md 迭代方式&quot;">​</a></h2><p>每次对话结束后，提醒 Hermes 对 <code>soul.md</code> 文件进行修改和迭代，持续优化人格设定。</p><h2 id="hindsight-部署-自建服务器" tabindex="-1">Hindsight 部署（自建服务器） <a class="header-anchor" href="#hindsight-部署-自建服务器" aria-label="Permalink to &quot;Hindsight 部署（自建服务器）&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># https://github.com/vectorize-io/hindsight</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 在服务器上部署 Hindsight，作为 hermes 的记忆系统</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 可导入第三方 API（此处使用 DeepSeek API）</span></span></code></pre></div><h2 id="搜索后端配置优先级" tabindex="-1">搜索后端配置优先级 <a class="header-anchor" href="#搜索后端配置优先级" aria-label="Permalink to &quot;搜索后端配置优先级&quot;">​</a></h2><ol><li><strong>主力</strong>：Tavily（付费但高质量，1000次/月免费）</li><li><strong>兜底</strong>：DuckDuckGo（免费零成本）</li></ol><h2 id="浏览器自动化" tabindex="-1">浏览器自动化 <a class="header-anchor" href="#浏览器自动化" aria-label="Permalink to &quot;浏览器自动化&quot;">​</a></h2><p>Hermes 已内置 Browser Use，只需安装 CamoFox：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># https://github.com/jo-inc/camofox-browser</span></span></code></pre></div><h2 id="工具链对比表" tabindex="-1">工具链对比表 <a class="header-anchor" href="#工具链对比表" aria-label="Permalink to &quot;工具链对比表&quot;">​</a></h2><table tabindex="0"><thead><tr><th>工具</th><th>类别</th><th>说明</th></tr></thead><tbody><tr><td>Jina Reader</td><td>单页抓取</td><td><code>r.jina.ai/</code> 前缀</td></tr><tr><td>Crawl4AI</td><td>批量抓取</td><td>Playwright + 本地模型结构化提取</td></tr><tr><td>Scrapling</td><td>反爬</td><td>Hermes optional-skill 内置</td></tr><tr><td>CamoFox</td><td>隐身浏览器</td><td>需单独安装</td></tr><tr><td>Tavily</td><td>AI搜索</td><td>主力</td></tr><tr><td>DuckDuckGo</td><td>搜索</td><td>兜底</td></tr></tbody></table><h2 id="文档处理" tabindex="-1">文档处理 <a class="header-anchor" href="#文档处理" aria-label="Permalink to &quot;文档处理&quot;">​</a></h2><table tabindex="0"><thead><tr><th>工具</th><th>说明</th></tr></thead><tbody><tr><td><strong>Pandoc</strong></td><td>万能格式转换（PDF/DOCX/HTML/EPUB → Markdown 等）</td></tr><tr><td><strong>Marker</strong></td><td>PDF 转 Markdown 增强</td></tr></tbody></table><h2 id="token-成本拆解" tabindex="-1">Token 成本拆解 <a class="header-anchor" href="#token-成本拆解" aria-label="Permalink to &quot;Token 成本拆解&quot;">​</a></h2><p><strong>hermes-dashboard</strong>：能按组件拆解 Token 消耗——系统提示占多少、工具定义占多少、消息历史占多少。</p><ul><li><a href="https://github.com/Bichev/hermes-dashboard" target="_blank" rel="noreferrer">https://github.com/Bichev/hermes-dashboard</a></li></ul><h2 id="自我进化注意事项" tabindex="-1">自我进化注意事项 <a class="header-anchor" href="#自我进化注意事项" aria-label="Permalink to &quot;自我进化注意事项&quot;">​</a></h2><ul><li>等系统稳定两周后再开启</li><li>建议搭配一个验证 cron，防止优化循环把还没调好的配置&quot;优化&quot;得更乱</li></ul><h2 id="rtk-安装地址" tabindex="-1">RTK 安装地址 <a class="header-anchor" href="#rtk-安装地址" aria-label="Permalink to &quot;RTK 安装地址&quot;">​</a></h2><ul><li><a href="https://github.com/adityahimaone/hermes-agent" target="_blank" rel="noreferrer">https://github.com/adityahimaone/hermes-agent</a></li></ul>`,22)])])}const u=a(i,[["render",s]]);export{b as __pageData,u as default};
